import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { teachersAPI } from '../../services/api';
import Card from '../../components/common/Card';
import toast from 'react-hot-toast';
import { User, Save, ToggleLeft, ToggleRight } from 'lucide-react';

const TeacherProfile = () => {
  const { user } = useAuth();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [formData, setFormData] = useState({});

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const response = await teachersAPI.getById(user.id);
      if (response.data.success) {
        setProfile(response.data.teacher);
        setFormData(response.data.teacher);
      }
    } catch (error) {
      console.error('Error fetching profile:', error);
      toast.error('Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({ 
      ...prev, 
      [name]: type === 'checkbox' ? checked : value 
    }));
  };

  const handleExpertiseChange = (exp) => {
    const current = formData.expertise || [];
    if (current.includes(exp)) {
      setFormData(prev => ({
        ...prev,
        expertise: current.filter(e => e !== exp)
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        expertise: [...current, exp]
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await teachersAPI.update(profile.id, formData);
      toast.success('Profile updated successfully');
      setEditMode(false);
      fetchProfile();
    } catch (error) {
      toast.error('Failed to update profile');
    } finally {
      setSaving(false);
    }
  };

  const toggleCapstoneAvailability = async () => {
    try {
      await teachersAPI.toggleCapstoneAvailability(
        profile.id, 
        !profile.capstone_adviser_available,
        formData.capstone_schedule
      );
      toast.success('Capstone availability updated');
      fetchProfile();
    } catch (error) {
      toast.error('Failed to update availability');
    }
  };

  if (loading) {
    return <div className="text-center py-10">Loading...</div>;
  }

  const expertiseOptions = [
    'Web Development', 'Mobile Development', 'Data Science', 
    'Networking', 'AI / Machine Learning', 'Cybersecurity',
    'Database Management', 'Cloud Computing', 'IoT'
  ];

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-secondary-800">My Profile</h1>
        <button
          onClick={() => setEditMode(!editMode)}
          className={`px-4 py-2 rounded-lg font-medium transition-colors ${
            editMode
              ? 'bg-secondary-200 text-secondary-700'
              : 'bg-primary-600 text-white hover:bg-primary-700'
          }`}
        >
          {editMode ? 'Cancel' : 'Edit Profile'}
        </button>
      </div>

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Profile Picture */}
          <Card>
            <div className="text-center">
              <div className="w-32 h-32 bg-blue-100 rounded-full mx-auto mb-4 flex items-center justify-center overflow-hidden">
                {profile?.profile_picture ? (
                  <img
                    src={profile.profile_picture}
                    alt="Profile"
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <User className="w-16 h-16 text-blue-400" />
                )}
              </div>
              <p className="text-secondary-600 font-medium">
                {profile?.first_name} {profile?.last_name}
              </p>
              <p className="text-secondary-500 text-sm">{profile?.position}</p>
              <p className="text-secondary-500 text-sm">{profile?.email}</p>
            </div>
          </Card>

          {/* Personal Information */}
          <Card title="Personal Information" className="lg:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="label">First Name</label>
                <input
                  type="text"
                  name="first_name"
                  value={formData.first_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Middle Name</label>
                <input
                  type="text"
                  name="middle_name"
                  value={formData.middle_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Last Name</label>
                <input
                  type="text"
                  name="last_name"
                  value={formData.last_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Gender</label>
                <select
                  name="gender"
                  value={formData.gender || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                >
                  <option value="">Select Gender</option>
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                  <option value="Other">Other</option>
                </select>
              </div>
              <div>
                <label className="label">Email</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
            </div>
          </Card>

          {/* Academic Assignment */}
          <Card title="Academic Assignment">
            <div className="space-y-4">
              <div>
                <label className="label">Section Advisory</label>
                <input
                  type="text"
                  name="section_advisory"
                  value={formData.section_advisory || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Courses Handled</label>
                  <textarea
                  name="courses_handled"
                  value={formData.courses_handled || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  rows={3}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Position</label>
                <select
                  name="position"
                  value={formData.position || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                >
                  <option value="Instructor">Instructor</option>
                  <option value="Adviser">Adviser</option>
                  <option value="Chairman">Chairman</option>
                  <option value="Dean">Dean</option>
                </select>
              </div>
            </div>
          </Card>

          {/* Employment Details */}
          <Card title="Employment Details">
            <div className="space-y-4">
              <div>
                <label className="label">Years of Service</label>
                <input
                  type="number"
                  name="years_of_service"
                  value={formData.years_of_service || 0}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Employment Status</label>
                <select
                  name="employment_status"
                  value={formData.employment_status || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                >
                  <option value="Full Time">Full Time</option>
                  <option value="Part Time">Part Time</option>
                </select>
              </div>
            </div>
          </Card>

          {/* Educational Background */}
          <Card title="Educational Background">
            <div className="space-y-4">
              <div>
                <label className="label">Degree</label>
                <input
                  type="text"
                  name="degree"
                  value={formData.degree || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">University</label>
                <input
                  type="text"
                  name="university"
                  value={formData.university || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
              <div>
                <label className="label">Year Graduated</label>
                <input
                  type="number"
                  name="year_graduated"
                  value={formData.year_graduated || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50"
                />
              </div>
            </div>
          </Card>

          {/* Expertise */}
          <Card title="Areas of Expertise">
            <div className="flex flex-wrap gap-2">
              {expertiseOptions.map((exp) => (
                <button
                  key={exp}
                  type="button"
                  onClick={() => editMode && handleExpertiseChange(exp)}
                  className={`px-3 py-1 rounded-full text-sm font-medium transition-colors ${
                    (formData.expertise || []).includes(exp)
                      ? 'bg-blue-600 text-white'
                      : 'bg-secondary-100 text-secondary-600 hover:bg-secondary-200'
                  } ${!editMode && 'cursor-default'}`}
                >
                  {exp}
                </button>
              ))}
            </div>
          </Card>

          {/* Capstone Availability */}
          <Card title="Capstone Adviser Availability">
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <span className="text-secondary-600">Available for Capstone Advising</span>
                <button
                  type="button"
                  onClick={toggleCapstoneAvailability}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${
                    profile?.capstone_adviser_available
                      ? 'bg-green-100 text-green-700'
                      : 'bg-secondary-100 text-secondary-600'
                  }`}
                >
                  {profile?.capstone_adviser_available ? (
                    <>
                      <ToggleRight className="w-5 h-5" />
                      Available
                    </>
                  ) : (
                    <>
                      <ToggleLeft className="w-5 h-5" />
                      Unavailable
                    </>
                  )}
                </button>
              </div>
              {profile?.capstone_adviser_available && (
                <div>
                  <label className="label">Available Schedule</label>
                  <textarea
                    name="capstone_schedule"
                    value={formData.capstone_schedule || ''}
                    onChange={handleChange}
                    disabled={!editMode}
                    rows={2}
                    placeholder="e.g., Mon-Fri 2PM-5PM"
                    className="input-field disabled:bg-secondary-50"
                  />
                </div>
              )}
            </div>
          </Card>
        </div>

        {editMode && (
          <div className="mt-6 flex justify-end">
            <button
              type="submit"
              disabled={saving}
              className="btn-primary flex items-center gap-2"
            >
              <Save className="w-4 h-4" />
              {saving ? 'Saving...' : 'Save Changes'}
            </button>
          </div>
        )}
      </form>
    </div>
  );
};

export default TeacherProfile;
